 FUNCTION: computeCci(Graph: G) {
 INT: i, j, n, sum
 n  G.number_of_nodes();
 INT: matrix[n][n]
 FLOAT: cci[n]
 matrix  distanceMatrix(G);
 FOR (i  1; i ≤ n; i  i + 1) {
 sum  0;
 FOR (j  1; j ≤ n; j  j + 1) {
 sum  sum + matrix[i][j];
 }
