 import java.util.Locale;

 class EditDistance {
 private final String baseWord;

 EditDistance(String baseWord) {
 this.baseWord = baseWord.toLowerCase(Locale.ENGLISH);
 }

 private int getSubstitutionCost(char a, char b) {
 return a ___D___ b ? 0 : 2;
 }

